import { useEffect, useState } from 'react';
import Layout from '../components/Layout';
import { bolgeAPI } from '../api';

export default function BolgeStoklar() {
  const [stoklar, setStoklar] = useState([]);
  const [loading, setLoading] = useState(true);
  const [filtre, setFiltre] = useState('');
  const [tipFiltre, setTipFiltre] = useState('');

  useEffect(() => {
    bolgeAPI.getStoklar()
      .then(r => setStoklar(r.data))
      .catch(() => {})
      .finally(() => setLoading(false));
  }, []);

  const filtered = stoklar.filter(s => {
    const aramaUygun = !filtre ||
      s.urun_adi.toLowerCase().includes(filtre.toLowerCase()) ||
      s.merkez_adi.toLowerCase().includes(filtre.toLowerCase()) ||
      s.merkez_il.toLowerCase().includes(filtre.toLowerCase());
    const tipUygun = !tipFiltre || s.merkez_tip === tipFiltre;
    return aramaUygun && tipUygun;
  });

  return (
    <Layout title="Bölge Stok Durumu">
      <div className="card">
        <div className="card-header">
          <div className="card-title">Stoklar ({filtered.length} kalem)</div>
          <div style={{ display: 'flex', gap: 8 }}>
            <select
              className="form-control"
              style={{ width: 160 }}
              value={tipFiltre}
              onChange={e => setTipFiltre(e.target.value)}
            >
              <option value="">Tüm Merkezler</option>
              <option value="toplama">Toplama</option>
              <option value="dagitim">Dağıtım</option>
            </select>
            <input
              className="form-control"
              placeholder="Ara (ürün, merkez, il...)"
              style={{ width: 220 }}
              value={filtre}
              onChange={e => setFiltre(e.target.value)}
            />
          </div>
        </div>

        {loading ? (
          <div className="loading"><div className="spinner" /> Yükleniyor...</div>
        ) : filtered.length === 0 ? (
          <div className="empty-state">
            <div className="empty-icon">📦</div>
            <div className="empty-text">Stok bulunamadı</div>
          </div>
        ) : (
          <div className="table-wrapper">
            <table>
              <thead>
                <tr>
                  <th>Ürün Adı</th>
                  <th>Marka</th>
                  <th>Kategori</th>
                  <th>Adet</th>
                  <th>Birim</th>
                  <th>Merkez</th>
                  <th>İl</th>
                  <th>Tip</th>
                </tr>
              </thead>
              <tbody>
                {filtered.map(s => (
                  <tr key={s.id}>
                    <td><strong>{s.urun_adi}</strong></td>
                    <td>{s.marka || '—'}</td>
                    <td>{s.kategori || '—'}</td>
                    <td style={{ fontFamily: 'IBM Plex Mono', fontWeight: 600 }}>{s.adet.toLocaleString('tr-TR')}</td>
                    <td>{s.birim}</td>
                    <td>{s.merkez_adi}</td>
                    <td>{s.merkez_il}</td>
                    <td>
                      <span className={`badge ${s.merkez_tip === 'toplama' ? 'badge-info' : 'badge-success'}`}>
                        {s.merkez_tip === 'toplama' ? 'Toplama' : 'Dağıtım'}
                      </span>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        )}
      </div>
    </Layout>
  );
}
